2091:      allocated range.  */
2092:   if (probe_range == 0)
2093:     probe_range = probe_interval - GET_MODE_SIZE (word_mode);
2094: 
2095:   if (rounded_size != CONST0_RTX (Pmode))
2096:     {
2097:       if (CONST_INT_P (rounded_size)
2098: 	  && INTVAL (rounded_size) <= 4 * probe_interval)
2099: 	{
2100: 	  for (HOST_WIDE_INT i = 0;
2101: 	       i < INTVAL (rounded_size);
2102: 	       i += probe_interval)
2103: 	    {
2104: 	      anti_adjust_stack (GEN_INT (probe_interval));
